158→        AnnouncementEntity announcement = announcementMapper.selectById(ro.getAnnouncementId());
159→        if (announcement != null) {
160→            if (ro.getStatus() != null) {
161→                announcement.setStatus(ro.getStatus());
162→            }
163→            if (ro.getType() != null) {
