171→    @Override
172→    public GetListAnnouncementVo getLastAnnouncement() {
173→        GetListAnnouncementVo vo =  new GetListAnnouncementVo();
174→        List<AnnouncementEntity> announcementList = announcementMapper.selectList(new QueryWrapper<AnnouncementEntity>()
175→                .lambda().eq(AnnouncementEntity::getStatus, AnnouncementStatus.PUBLISHED.getCode()).
176→                eq(AnnouncementEntity::getIsDeleted, false).eq(AnnouncementEntity::getType, AnnouncementType.TIMED.getCode())
177→                .orderByDesc(AnnouncementEntity::getCreatedAt));
178→        AnnouncementEntity announcement = announcementList == null || announcementList.isEmpty() ? null : announcementList.getFirst();
179→
180→        if (announcement != null) {
181→            // 判断用户是否已读公告,读过公告，返回空
182→            boolean hasRead = announcementReadRecordMapper.selectList(new QueryWrapper<AnnouncementReadRecordEntity>()
183→                    .lambda().eq(AnnouncementReadRecordEntity::getUserId, SessionContext.getUserId())
184→                    .eq(AnnouncementReadRecordEntity::getAnnouncementId, announcement.getId())) != null;
185→            if (hasRead) {
186→                return  vo;
187→            }
188→            vo.setTitle(announcement.getTitle());
189→            vo.setContent(announcement.getContent());
190→            vo.setPublishTime(announcement.getPublishTime());
191→            vo.setIsPopup(announcement.getIsPopup());
192→            vo.setId(announcement.getId());
193→            // 增加用户读取公告的记录
194→            addAnnouncementReadRecord(vo.getId());
195→        }
196→
197→        return vo;
198→
199→    }
