201→    @Override
202→    public void addAnnouncementReadRecord(Long id) {
203→        AnnouncementReadRecordEntity readRecord = new AnnouncementReadRecordEntity();
204→        readRecord.setUserId(SessionContext.getUserId());
205→        readRecord.setAnnouncementId(id);
206→        readRecord.setReadTime(LocalDateTime.now());
207→        // 先判断是否record是否存在，不存在创建，存在跳过
208→        AnnouncementReadRecordEntity existedAnnouncementReadRecordEntity =
209→                announcementReadRecordManager.selectByAnnouncementIdAndUserId(id, SessionContext.getUserId());
210→        if (existedAnnouncementReadRecordEntity == null) {
211→            announcementReadRecordMapper.insert(readRecord);
212→        }
213→
214→    }
