278→    public List<GetListAnnouncementVo> getAnnouncementById(List<Long> announcementIdListList) {
279→        List<GetListAnnouncementVo> voList = new ArrayList<>();
280→        List<AnnouncementEntity> list = announcementMapper.selectBatchIds(announcementIdListList);
281→        list.forEach(entity -> {
282→            GetListAnnouncementVo vo = new GetListAnnouncementVo();
283→            vo.setId(entity.getId());
284→            vo.setTitle(entity.getTitle());
285→            vo.setContent(entity.getContent());
286→            vo.setPublishTime(entity.getPublishTime());
287→            vo.setIsPopup(entity.getIsPopup());
288→            vo.setStatus(entity.getStatus());
289→            vo.setCreatorId(entity.getCreatorId());
290→            voList.add(vo);
291→        });
292→        return voList;
293→    }
