295→    private AnnouncementEntity createNewAnnouncement(CreateAnnouncementRo ro) {
296→        AnnouncementEntity announcement = new AnnouncementEntity();
297→        announcement.setTitle(ro.getTitle());
298→        announcement.setContent(ro.getContent());
299→        announcement.setIsPopup(ro.getIsPopup() != null ? ro.getIsPopup() : false);
300→        announcement.setType(AnnouncementType.TIMED.getCode());
301→        announcement.setStatus(AnnouncementStatus.WAITING.getCode());
302→
303→        // 设置创建人信息
304→        Long userId = SessionContext.getUserId();
305→        announcement.setCreatorId(userId);
306→        UserSimpleInfoVo userInfo = apitableGrpcClientService.getUserById(userId);
307→        // 假设从SecurityContext获取当前用户信息
308→        if (userInfo != null) {
309→            announcement.setCreatorName(userInfo.getNickName());
310→        } else {
311→            announcement.setCreatorName("");
312→        }
313→
314→        return announcement;
315→    }
